package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"
)

func main() {
	var server http.Server
	var port int
	var err error

	portFlag := flag.Int("p", 3318, "port to listen on")
	schemaFile := flag.String("s", "", "document schema file")
	tokenFile := flag.String("t", "", "token file")
	flag.Parse()

	if *schemaFile == "" {
		slog.Error("missing required -s schema file argument")
		os.Exit(1)
	}

	schemaData, readErr := os.ReadFile(*schemaFile)
	if readErr != nil {
		slog.Error("unable to read schema file", "file", *schemaFile, "error", readErr)
		os.Exit(1)
	}
	var schema any
	if err = json.Unmarshal(schemaData, &schema); err != nil {
		slog.Error("invalid schema JSON", "file", *schemaFile, "error", err)
		os.Exit(1)
	}

	tokens := map[string]string{}
	if *tokenFile != "" {
		data, tokenReadErr := os.ReadFile(*tokenFile)
		if tokenReadErr != nil {
			slog.Error("unable to read token file", "file", *tokenFile, "error", tokenReadErr)
			os.Exit(1)
		}
		if err = json.Unmarshal(data, &tokens); err != nil {
			slog.Error("invalid token file", "file", *tokenFile, "error", err)
			os.Exit(1)
		}
	}
	app := newApp(schema, tokens)

	port = *portFlag
	server = http.Server{
		Addr:    fmt.Sprintf(":%d", port),
		Handler: app,
	}

	// The following code should go last and remain unchanged.
	// Note that you must actually initialize 'server' and 'port'
	// before this.  Note that the server is started below by
	// calling ListenAndServe.  You must not start the server
	// before this.

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

package main

import (
	"crypto/rand"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"reflect"
	"sort"
	"strconv"
	"strings"
	"sync"
	"sync/atomic"
	"time"
)

type metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

type document struct {
	Raw         json.RawMessage
	Meta        metadata
	Collections map[string]*collection
}

type collection struct {
	Docs map[string]*document
}

type database struct {
	Top *collection
}

type tokenInfo struct {
	Username string
	Expires  time.Time
}

type sseEvent struct {
	Event string
	Data  string
	ID    int64
}

type colSubscriber struct {
	ch   chan sseEvent
	low  string
	high string
}

type subscriptionHub struct {
	mu      sync.RWMutex
	nextID  int
	docSubs map[string]map[int]chan sseEvent
	colSubs map[string]map[int]colSubscriber
}

func newSubscriptionHub() *subscriptionHub {
	return &subscriptionHub{
		docSubs: make(map[string]map[int]chan sseEvent),
		colSubs: make(map[string]map[int]colSubscriber),
	}
}

func (h *subscriptionHub) addDoc(path string) (int, chan sseEvent) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.nextID++
	id := h.nextID
	ch := make(chan sseEvent, 32)
	if h.docSubs[path] == nil {
		h.docSubs[path] = make(map[int]chan sseEvent)
	}
	h.docSubs[path][id] = ch
	return id, ch
}

func (h *subscriptionHub) removeDoc(path string, id int) {
	h.mu.Lock()
	defer h.mu.Unlock()
	subs := h.docSubs[path]
	if subs == nil {
		return
	}
	if ch := subs[id]; ch != nil {
		close(ch)
		delete(subs, id)
	}
	if len(subs) == 0 {
		delete(h.docSubs, path)
	}
}

func (h *subscriptionHub) addCollection(path, low, high string) (int, chan sseEvent) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.nextID++
	id := h.nextID
	ch := make(chan sseEvent, 32)
	if h.colSubs[path] == nil {
		h.colSubs[path] = make(map[int]colSubscriber)
	}
	h.colSubs[path][id] = colSubscriber{ch: ch, low: low, high: high}
	return id, ch
}

func (h *subscriptionHub) removeCollection(path string, id int) {
	h.mu.Lock()
	defer h.mu.Unlock()
	subs := h.colSubs[path]
	if subs == nil {
		return
	}
	if sub, ok := subs[id]; ok {
		close(sub.ch)
		delete(subs, id)
	}
	if len(subs) == 0 {
		delete(h.colSubs, path)
	}
}

func (h *subscriptionHub) publishDocument(path string, ev sseEvent) {
	h.mu.RLock()
	subs := h.docSubs[path]
	for _, ch := range subs {
		select {
		case ch <- ev:
		default:
		}
	}
	h.mu.RUnlock()
}

func (h *subscriptionHub) publishCollection(path, docName string, ev sseEvent) {
	h.mu.RLock()
	subs := h.colSubs[path]
	for _, sub := range subs {
		if docName != "" && !inRange(docName, sub.low, sub.high) {
			continue
		}
		select {
		case sub.ch <- ev:
		default:
		}
	}
	h.mu.RUnlock()
}

type app struct {
	mu       sync.RWMutex
	dbs      map[string]*database
	tokens   map[string]tokenInfo
	schema   any
	handler  http.Handler
	subHub   *subscriptionHub
	idCtr    uint64
}

type docResponse struct {
	Path string          `json:"path"`
	Doc  json.RawMessage `json:"doc"`
	Meta metadata        `json:"meta"`
}

func newApp(schema any, seededTokens map[string]string) *app {
	a := &app{
		dbs:    make(map[string]*database),
		tokens: make(map[string]tokenInfo),
		schema: schema,
		subHub: newSubscriptionHub(),
	}

	if len(seededTokens) > 0 {
		expires := time.Now().Add(48 * time.Hour)
		for user, tok := range seededTokens {
			a.tokens[tok] = tokenInfo{Username: user, Expires: expires}
		}
	}

	mux := http.NewServeMux()
	mux.HandleFunc("/auth", a.handleAuth)
	mux.HandleFunc("/v1/", a.handleV1)
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		a.respondError(w, http.StatusNotFound, "Not Found")
	})
	a.handler = withCommonHeaders(mux)
	return a
}

func withCommonHeaders(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type")
		w.Header().Set("Access-Control-Allow-Methods", "GET,POST,PUT,PATCH,DELETE,OPTIONS")
		w.Header().Set("Access-Control-Expose-Headers", "Location")
		next.ServeHTTP(w, r)
	})
}

func (a *app) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	a.handler.ServeHTTP(w, r)
}

func (a *app) respondJSON(w http.ResponseWriter, status int, value any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(value)
}

func (a *app) respondNoContent(w http.ResponseWriter) {
	w.WriteHeader(http.StatusNoContent)
}

func (a *app) respondError(w http.ResponseWriter, status int, msg string) {
	a.respondJSON(w, status, map[string]string{"error": msg})
}

func (a *app) parseBearer(r *http.Request) string {
	h := strings.TrimSpace(r.Header.Get("Authorization"))
	if h == "" {
		return ""
	}
	parts := strings.Fields(h)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
		return ""
	}
	return parts[1]
}

func (a *app) requireAuth(w http.ResponseWriter, r *http.Request) (string, bool) {
	token := a.parseBearer(r)
	if token == "" {
		a.respondError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	a.mu.RLock()
	info, ok := a.tokens[token]
	a.mu.RUnlock()
	if !ok || time.Now().After(info.Expires) {
		a.respondError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	return info.Username, true
}

func (a *app) usernameFromToken(r *http.Request) string {
	token := a.parseBearer(r)
	a.mu.RLock()
	info := a.tokens[token]
	a.mu.RUnlock()
	return info.Username
}

func (a *app) generateToken() (string, error) {
	b := make([]byte, 18)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(b), nil
}

func (a *app) handleAuth(w http.ResponseWriter, r *http.Request) {
	if r.Method == http.MethodOptions {
		w.WriteHeader(http.StatusOK)
		return
	}

	switch r.Method {
	case http.MethodPost:
		var req struct {
			Username string `json:"username"`
		}
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			a.respondError(w, http.StatusBadRequest, "Malformed request body")
			return
		}
		if strings.TrimSpace(req.Username) == "" {
			a.respondError(w, http.StatusBadRequest, "No username in request body")
			return
		}
		tok, err := a.generateToken()
		if err != nil {
			a.respondError(w, http.StatusInternalServerError, "Failed to generate token")
			return
		}
		a.mu.Lock()
		a.tokens[tok] = tokenInfo{Username: req.Username, Expires: time.Now().Add(time.Hour)}
		a.mu.Unlock()
		a.respondJSON(w, http.StatusOK, map[string]string{"token": tok})
	case http.MethodDelete:
		token := a.parseBearer(r)
		if token == "" {
			a.respondError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
		a.mu.Lock()
		if _, ok := a.tokens[token]; !ok {
			a.mu.Unlock()
			a.respondError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
		delete(a.tokens, token)
		a.mu.Unlock()
		a.respondNoContent(w)
	default:
		a.respondError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

type parsedV1Path struct {
	database  string
	parts     []string
	trailing  bool
	resource  string // database|collection|document
	fullPath  string
	docName   string
	collParts []string
	docParts  []string
}

func parseV1Path(urlPath string) (parsedV1Path, error) {
	if !strings.HasPrefix(urlPath, "/v1/") {
		return parsedV1Path{}, errors.New("invalid API path")
	}
	rel := strings.TrimPrefix(urlPath, "/v1/")
	if rel == "" {
		return parsedV1Path{}, errors.New("missing database name")
	}
	trailing := strings.HasSuffix(rel, "/")
	if trailing {
		rel = strings.TrimSuffix(rel, "/")
	}
	if rel == "" {
		return parsedV1Path{}, errors.New("missing database name")
	}
	parts := strings.Split(rel, "/")
	for _, p := range parts {
		if p == "" {
			return parsedV1Path{}, errors.New("invalid empty path component")
		}
	}
	p := parsedV1Path{
		database: strings.TrimSpace(parts[0]),
		parts:    parts[1:],
		trailing: trailing,
		fullPath: "/v1/" + rel,
	}
	if p.database == "" {
		return parsedV1Path{}, errors.New("missing database name")
	}

	if !trailing && len(p.parts) == 0 {
		p.resource = "database"
		return p, nil
	}

	if trailing {
		if len(p.parts)%2 != 0 {
			return parsedV1Path{}, errors.New("invalid collection path")
		}
		p.resource = "collection"
		p.collParts = append([]string{}, p.parts...)
		return p, nil
	}

	if len(p.parts)%2 == 0 {
		return parsedV1Path{}, errors.New("invalid document path")
	}
	p.resource = "document"
	p.docName = p.parts[len(p.parts)-1]
	p.docParts = append([]string{}, p.parts...)
	p.collParts = append([]string{}, p.parts[:len(p.parts)-1]...)
	return p, nil
}

func (a *app) handleV1(w http.ResponseWriter, r *http.Request) {
	if r.Method == http.MethodOptions {
		pp, err := parseV1Path(r.URL.Path)
		allow := "GET, POST, PUT, PATCH, DELETE, OPTIONS"
		if err == nil {
			switch pp.resource {
			case "database":
				allow = "PUT, DELETE, OPTIONS"
			case "collection":
				allow = "GET, POST, PUT, DELETE, OPTIONS"
			case "document":
				allow = "GET, PUT, PATCH, DELETE, OPTIONS"
			}
		}
		w.Header().Set("Allow", allow)
		w.WriteHeader(http.StatusOK)
		return
	}

	_, authOK := a.requireAuth(w, r)
	if !authOK {
		return
	}

	pp, err := parseV1Path(r.URL.Path)
	if err != nil {
		a.respondError(w, http.StatusBadRequest, err.Error())
		return
	}

	switch pp.resource {
	case "database":
		a.handleDatabase(w, r, pp)
	case "collection":
		a.handleCollection(w, r, pp)
	case "document":
		a.handleDocument(w, r, pp)
	default:
		a.respondError(w, http.StatusBadRequest, "invalid path")
	}
}

func (a *app) handleDatabase(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	switch r.Method {
	case http.MethodPut:
		a.mu.Lock()
		if _, exists := a.dbs[p.database]; exists {
			a.mu.Unlock()
			a.respondError(w, http.StatusConflict, "Database already exists")
			return
		}
		a.dbs[p.database] = &database{Top: &collection{Docs: make(map[string]*document)}}
		a.mu.Unlock()
		uri := "/v1/" + p.database
		w.Header().Set("Location", uri)
		a.respondJSON(w, http.StatusCreated, map[string]string{"uri": uri})
	case http.MethodDelete:
		a.mu.Lock()
		if _, exists := a.dbs[p.database]; !exists {
			a.mu.Unlock()
			a.respondError(w, http.StatusNotFound, "Database does not exist")
			return
		}
		delete(a.dbs, p.database)
		a.mu.Unlock()
		a.respondNoContent(w)
		topCollectionPath := buildCollectionPath(p.database, nil)
		a.subHub.publishCollection(topCollectionPath, "", makeDeleteEvent(topCollectionPath))
	default:
		a.respondError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (a *app) handleCollection(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	switch r.Method {
	case http.MethodGet:
		a.handleCollectionGet(w, r, p)
	case http.MethodPost:
		a.handleCollectionPost(w, r, p)
	case http.MethodPut:
		if len(p.collParts) == 0 {
			p.resource = "database"
			a.handleDatabase(w, r, p)
			return
		}
		a.handleCollectionPut(w, r, p)
	case http.MethodDelete:
		if len(p.collParts) == 0 {
			p.resource = "database"
			a.handleDatabase(w, r, p)
			return
		}
		a.handleCollectionDelete(w, r, p)
	default:
		a.respondError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (a *app) getCollection(db *database, path []string) (*collection, bool) {
	cur := db.Top
	if len(path) == 0 {
		return cur, true
	}
	for i := 0; i < len(path); i += 2 {
		doc := cur.Docs[path[i]]
		if doc == nil {
			return nil, false
		}
		next := doc.Collections[path[i+1]]
		if next == nil {
			return nil, false
		}
		cur = next
	}
	return cur, true
}

func parseInterval(raw string) (low string, high string, ok bool) {
	if raw == "" {
		return "", "", true
	}
	if !strings.HasPrefix(raw, "[") || !strings.HasSuffix(raw, "]") {
		return "", "", false
	}
	middle := strings.TrimSuffix(strings.TrimPrefix(raw, "["), "]")
	comma := strings.Index(middle, ",")
	if comma < 0 {
		return "", "", false
	}
	low = middle[:comma]
	high = middle[comma+1:]
	return low, high, true
}

func inRange(name, low, high string) bool {
	if low != "" && name < low {
		return false
	}
	if high != "" && name > high {
		return false
	}
	return true
}

func buildDocPath(dbName string, parent []string, docName string) string {
	if len(parent) == 0 {
		return "/v1/" + dbName + "/" + docName
	}
	return "/v1/" + dbName + "/" + strings.Join(append(append([]string{}, parent...), docName), "/")
}

func (a *app) handleCollectionGet(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	low, high, ok := parseInterval(r.URL.Query().Get("interval"))
	if !ok {
		a.respondError(w, http.StatusBadRequest, "Malformed interval query")
		return
	}
	mode := r.URL.Query().Get("mode")
	if mode != "" && mode != "subscribe" {
		a.respondError(w, http.StatusBadRequest, "Invalid mode")
		return
	}

	a.mu.RLock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.RUnlock()
		if len(p.collParts) == 0 {
			a.respondError(w, http.StatusNotFound, "Database does not exist")
		} else {
			a.respondError(w, http.StatusNotFound, "Collection does not exist")
		}
		return
	}
	coll, found := a.getCollection(db, p.collParts)
	if !found {
		a.mu.RUnlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
		return
	}

	names := make([]string, 0, len(coll.Docs))
	for name := range coll.Docs {
		if inRange(name, low, high) {
			names = append(names, name)
		}
	}
	sort.Strings(names)

	out := make([]docResponse, 0, len(names))
	for _, name := range names {
		d := coll.Docs[name]
		out = append(out, docResponse{
			Path: buildDocPath(p.database, p.collParts, name),
			Doc:  append(json.RawMessage(nil), d.Raw...),
			Meta: d.Meta,
		})
	}
	a.mu.RUnlock()

	if mode == "subscribe" {
		flusher, ok := w.(http.Flusher)
		if !ok {
			a.respondError(w, http.StatusInternalServerError, "streaming unsupported")
			return
		}
		w.Header().Set("Content-Type", "text/event-stream")
		w.Header().Set("Cache-Control", "no-cache")
		w.Header().Set("Connection", "keep-alive")
		w.WriteHeader(http.StatusOK)
		flusher.Flush()
		for _, d := range out {
			writeSSE(w, flusher, makeUpdateEvent(d))
		}
		subPath := buildCollectionPath(p.database, p.collParts)
		subID, ch := a.subHub.addCollection(subPath, low, high)
		defer a.subHub.removeCollection(subPath, subID)
		ticker := time.NewTicker(15 * time.Second)
		defer ticker.Stop()
		ctx := r.Context()
		for {
			select {
			case <-ctx.Done():
				return
			case ev := <-ch:
				writeSSE(w, flusher, ev)
			case <-ticker.C:
				writeSSEComment(w, flusher, "keep-alive")
			}
		}
	}

	a.respondJSON(w, http.StatusOK, out)
}

func (a *app) handleDocument(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	switch r.Method {
	case http.MethodGet:
		a.handleDocumentGet(w, r, p)
	case http.MethodPut:
		a.handleDocumentPut(w, r, p)
	case http.MethodDelete:
		a.handleDocumentDelete(w, r, p)
	case http.MethodPatch:
		a.handleDocumentPatch(w, r, p)
	default:
		a.respondError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func decodeJSONBody(r *http.Request, dst any) error {
	b, err := io.ReadAll(r.Body)
	if err != nil {
		return err
	}
	if len(strings.TrimSpace(string(b))) == 0 {
		return errors.New("empty body")
	}
	if err := json.Unmarshal(b, dst); err != nil {
		return err
	}
	return nil
}

func (a *app) nextID() string {
	id := atomic.AddUint64(&a.idCtr, 1)
	return fmt.Sprintf("%d", id)
}

func copyRaw(raw json.RawMessage) json.RawMessage {
	return append(json.RawMessage(nil), raw...)
}

func (a *app) validateDocument(raw []byte) error {
	var value any
	if err := json.Unmarshal(raw, &value); err != nil {
		return err
	}
	if !validateWithSchema(value, a.schema) {
		return errors.New("document does not conform to schema")
	}
	return nil
}

func validateWithSchema(value any, schema any) bool {
	m, ok := schema.(map[string]any)
	if !ok {
		return true
	}

	if oneOf, ok := m["oneOf"].([]any); ok {
		for _, sub := range oneOf {
			if validateWithSchema(value, sub) {
				return true
			}
		}
		return false
	}
	if anyOf, ok := m["anyOf"].([]any); ok {
		for _, sub := range anyOf {
			if validateWithSchema(value, sub) {
				return true
			}
		}
		return false
	}

	if typ, ok := m["type"].(string); ok {
		switch typ {
		case "object":
			obj, ok := value.(map[string]any)
			if !ok {
				return false
			}
			if req, ok := m["required"].([]any); ok {
				for _, r := range req {
					name, ok := r.(string)
					if !ok {
						continue
					}
					if _, exists := obj[name]; !exists {
						return false
					}
				}
			}
			props, _ := m["properties"].(map[string]any)
			if props != nil {
				for name, sub := range props {
					if v, exists := obj[name]; exists {
						if !validateWithSchema(v, sub) {
							return false
						}
					}
				}
			}
			if ap, ok := m["additionalProperties"]; ok {
				switch apv := ap.(type) {
				case bool:
					if !apv {
						for k := range obj {
							if props == nil || props[k] == nil {
								return false
							}
						}
					}
				default:
					for k, v := range obj {
						if props != nil && props[k] != nil {
							continue
						}
						if !validateWithSchema(v, apv) {
							return false
						}
					}
				}
			}
		case "array":
			arr, ok := value.([]any)
			if !ok {
				return false
			}
			if itemSchema, ok := m["items"]; ok {
				for _, item := range arr {
					if !validateWithSchema(item, itemSchema) {
						return false
					}
				}
			}
		case "string":
			if _, ok := value.(string); !ok {
				return false
			}
		case "number":
			if _, ok := value.(float64); !ok {
				return false
			}
		case "integer":
			f, ok := value.(float64)
			if !ok || f != float64(int64(f)) {
				return false
			}
		case "boolean":
			if _, ok := value.(bool); !ok {
				return false
			}
		case "null":
			if value != nil {
				return false
			}
		}
	}
	return true
}

func (a *app) getDocument(db *database, docPath []string) (*document, bool) {
	if len(docPath) == 0 || len(docPath)%2 == 0 {
		return nil, false
	}
	parent, ok := a.getCollection(db, docPath[:len(docPath)-1])
	if !ok {
		return nil, false
	}
	d := parent.Docs[docPath[len(docPath)-1]]
	return d, d != nil
}

func (a *app) getParentCollectionForDoc(db *database, docPath []string) (*collection, string, bool) {
	if len(docPath) == 0 || len(docPath)%2 == 0 {
		return nil, "", false
	}
	parent, ok := a.getCollection(db, docPath[:len(docPath)-1])
	if !ok {
		return nil, "", false
	}
	return parent, docPath[len(docPath)-1], true
}

func (a *app) handleDocumentPut(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	username := a.usernameFromToken(r)
	body, err := io.ReadAll(r.Body)
	if err != nil || len(strings.TrimSpace(string(body))) == 0 {
		a.respondError(w, http.StatusBadRequest, "Malformed request body")
		return
	}
	if !json.Valid(body) {
		a.respondError(w, http.StatusBadRequest, "Malformed request body")
		return
	}
	if err := a.validateDocument(body); err != nil {
		a.respondError(w, http.StatusBadRequest, "Document failed schema validation")
		return
	}
	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = "overwrite"
	}
	if mode != "overwrite" && mode != "nooverwrite" {
		a.respondError(w, http.StatusBadRequest, "Invalid mode")
		return
	}

	now := time.Now().UnixMilli()
	uri := "/v1/" + p.database + "/" + strings.Join(p.docParts, "/")
	parentPath := buildCollectionPath(p.database, p.collParts)
	docName := p.docParts[len(p.docParts)-1]

	a.mu.Lock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
		return
	}
	parent, name, ok := a.getParentCollectionForDoc(db, p.docParts)
	if !ok {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
		return
	}
	existing := parent.Docs[name]
	if existing != nil && mode == "nooverwrite" {
		a.mu.Unlock()
		a.respondError(w, http.StatusPreconditionFailed, "Document already exists")
		return
	}

	status := http.StatusCreated
	meta := metadata{
		CreatedBy:      username,
		CreatedAt:      now,
		LastModifiedBy: username,
		LastModifiedAt: now,
	}
	colls := map[string]*collection{}
	if existing != nil {
		status = http.StatusOK
		meta.CreatedBy = existing.Meta.CreatedBy
		meta.CreatedAt = existing.Meta.CreatedAt
		colls = existing.Collections
	}
	parent.Docs[name] = &document{
		Raw:         copyRaw(body),
		Meta:        meta,
		Collections: colls,
	}
	resp := docResponse{
		Path: uri,
		Doc:  copyRaw(body),
		Meta: meta,
	}
	a.mu.Unlock()
	w.Header().Set("Location", uri)
	a.respondJSON(w, status, map[string]string{"uri": uri})
	ev := makeUpdateEvent(resp)
	a.subHub.publishDocument(uri, ev)
	a.subHub.publishCollection(parentPath, docName, ev)
}

func (a *app) handleDocumentGet(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	mode := r.URL.Query().Get("mode")
	if mode != "" && mode != "subscribe" {
		a.respondError(w, http.StatusBadRequest, "Invalid mode")
		return
	}
	a.mu.RLock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.RUnlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	doc, ok := a.getDocument(db, p.docParts)
	if !ok {
		a.mu.RUnlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	resp := docResponse{
		Path: "/v1/" + p.database + "/" + strings.Join(p.docParts, "/"),
		Doc:  copyRaw(doc.Raw),
		Meta: doc.Meta,
	}
	a.mu.RUnlock()

	if mode == "subscribe" {
		flusher, ok := w.(http.Flusher)
		if !ok {
			a.respondError(w, http.StatusInternalServerError, "streaming unsupported")
			return
		}
		w.Header().Set("Content-Type", "text/event-stream")
		w.Header().Set("Cache-Control", "no-cache")
		w.Header().Set("Connection", "keep-alive")
		w.WriteHeader(http.StatusOK)
		flusher.Flush()
		docPath := "/v1/" + p.database + "/" + strings.Join(p.docParts, "/")
		writeSSE(w, flusher, makeUpdateEvent(resp))
		subID, ch := a.subHub.addDoc(docPath)
		defer a.subHub.removeDoc(docPath, subID)
		ticker := time.NewTicker(15 * time.Second)
		defer ticker.Stop()
		ctx := r.Context()
		for {
			select {
			case <-ctx.Done():
				return
			case ev := <-ch:
				writeSSE(w, flusher, ev)
			case <-ticker.C:
				writeSSEComment(w, flusher, "keep-alive")
			}
		}
	}
	a.respondJSON(w, http.StatusOK, resp)
}

func (a *app) handleDocumentDelete(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	a.mu.Lock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	parent, name, ok := a.getParentCollectionForDoc(db, p.docParts)
	if !ok {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	if parent.Docs[name] == nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	delete(parent.Docs, name)
	uri := "/v1/" + p.database + "/" + strings.Join(p.docParts, "/")
	parentPath := buildCollectionPath(p.database, p.collParts)
	a.mu.Unlock()
	a.respondNoContent(w)
	ev := makeDeleteEvent(uri)
	a.subHub.publishDocument(uri, ev)
	a.subHub.publishCollection(parentPath, name, ev)
}

func (a *app) handleCollectionPost(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	username := a.usernameFromToken(r)
	body, err := io.ReadAll(r.Body)
	if err != nil || len(strings.TrimSpace(string(body))) == 0 || !json.Valid(body) {
		a.respondError(w, http.StatusBadRequest, "Malformed request body")
		return
	}
	if err := a.validateDocument(body); err != nil {
		a.respondError(w, http.StatusBadRequest, "Document failed schema validation")
		return
	}

	now := time.Now().UnixMilli()
	a.mu.Lock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.Unlock()
		if len(p.collParts) == 0 {
			a.respondError(w, http.StatusNotFound, "Database does not exist")
		} else {
			a.respondError(w, http.StatusNotFound, "Collection does not exist")
		}
		return
	}
	coll, ok := a.getCollection(db, p.collParts)
	if !ok {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
		return
	}

	var name string
	for {
		name = "doc" + a.nextID()
		if coll.Docs[name] == nil {
			break
		}
	}
	coll.Docs[name] = &document{
		Raw: copyRaw(body),
		Meta: metadata{
			CreatedBy:      username,
			CreatedAt:      now,
			LastModifiedBy: username,
			LastModifiedAt: now,
		},
		Collections: make(map[string]*collection),
	}
	uri := buildDocPath(p.database, p.collParts, name)
	resp := docResponse{
		Path: uri,
		Doc:  copyRaw(body),
		Meta: coll.Docs[name].Meta,
	}
	parentPath := buildCollectionPath(p.database, p.collParts)
	a.mu.Unlock()
	w.Header().Set("Location", uri)
	a.respondJSON(w, http.StatusCreated, map[string]string{"uri": uri})
	a.subHub.publishDocument(uri, makeUpdateEvent(resp))
	a.subHub.publishCollection(parentPath, name, makeUpdateEvent(resp))
}

func buildCollectionPath(db string, collParts []string) string {
	if len(collParts) == 0 {
		return "/v1/" + db + "/"
	}
	return "/v1/" + db + "/" + strings.Join(collParts, "/") + "/"
}

func makeUpdateEvent(resp docResponse) sseEvent {
	data, _ := json.Marshal(resp)
	return sseEvent{
		Event: "update",
		Data:  string(data),
		ID:    time.Now().UnixMilli(),
	}
}

func makeDeleteEvent(path string) sseEvent {
	data, _ := json.Marshal(path)
	return sseEvent{
		Event: "delete",
		Data:  string(data),
		ID:    time.Now().UnixMilli(),
	}
}

func writeSSE(w http.ResponseWriter, flusher http.Flusher, ev sseEvent) {
	_, _ = fmt.Fprintf(w, "event: %s\n", ev.Event)
	_, _ = fmt.Fprintf(w, "data: %s\n", ev.Data)
	_, _ = fmt.Fprintf(w, "id: %d\n\n", ev.ID)
	flusher.Flush()
}

func writeSSEComment(w http.ResponseWriter, flusher http.Flusher, comment string) {
	_, _ = fmt.Fprintf(w, ": %s\n\n", comment)
	flusher.Flush()
}

func (a *app) handleCollectionPut(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	a.mu.Lock()
	defer a.mu.Unlock()
	db := a.dbs[p.database]
	if db == nil {
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	name := p.collParts[len(p.collParts)-1]
	parentDocPath := p.collParts[:len(p.collParts)-1]
	doc, ok := a.getDocument(db, parentDocPath)
	if !ok {
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	if doc.Collections[name] != nil {
		a.respondError(w, http.StatusConflict, "Collection already exists")
		return
	}
	doc.Collections[name] = &collection{Docs: make(map[string]*document)}
	uri := buildCollectionPath(p.database, p.collParts)
	w.Header().Set("Location", uri)
	a.respondJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

func (a *app) handleCollectionDelete(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	a.mu.Lock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
		return
	}
	name := p.collParts[len(p.collParts)-1]
	parentDocPath := p.collParts[:len(p.collParts)-1]
	doc, ok := a.getDocument(db, parentDocPath)
	if !ok {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Collection does not exist")
