	a.respondNoContent(w)
	a.subHub.publishCollection(collPath, "", makeDeleteEvent(collPath))
}

type patchOperation struct {
	Op    string `json:"op"`
	Path  string `json:"path"`
	Value any    `json:"value"`
}

func (a *app) handleDocumentPatch(w http.ResponseWriter, r *http.Request, p parsedV1Path) {
	username := a.usernameFromToken(r)
	uri := "/v1/" + p.database + "/" + strings.Join(p.docParts, "/")
	parentPath := buildCollectionPath(p.database, p.collParts)
	docName := p.docParts[len(p.docParts)-1]

	var patches []patchOperation
	if err := decodeJSONBody(r, &patches); err != nil {
		a.respondError(w, http.StatusBadRequest, "Malformed request body")
		return
	}

	a.mu.Lock()
	db := a.dbs[p.database]
	if db == nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}
	doc, ok := a.getDocument(db, p.docParts)
	if !ok {
		a.mu.Unlock()
		a.respondError(w, http.StatusNotFound, "Document does not exist")
		return
	}

	var working any
	if err := json.Unmarshal(doc.Raw, &working); err != nil {
		a.mu.Unlock()
		a.respondError(w, http.StatusBadRequest, "Malformed document")
		return
	}

	patchFailed := false
	message := "patch applied"
	for _, op := range patches {
		ok, msg := applyPatchOperation(&working, op)
		if !ok {
			patchFailed = true
			message = msg
			break
		}
	}

	var resp docResponse
	if !patchFailed {
		newRaw, err := json.Marshal(working)
		if err != nil || a.validateDocument(newRaw) != nil {
			patchFailed = true
			message = "patch failed"
		} else {
			doc.Raw = copyRaw(newRaw)
			doc.Meta.LastModifiedBy = username
			doc.Meta.LastModifiedAt = time.Now().UnixMilli()
			resp = docResponse{
				Path: uri,
				Doc:  copyRaw(doc.Raw),
				Meta: doc.Meta,
			}
		}
	}
	a.mu.Unlock()

	w.Header().Set("Location", uri)
	a.respondJSON(w, http.StatusOK, map[string]any{
		"uri":         uri,
		"patchFailed": patchFailed,
		"message":     message,
	})

	if !patchFailed {
		ev := makeUpdateEvent(resp)
		a.subHub.publishDocument(uri, ev)
		a.subHub.publishCollection(parentPath, docName, ev)
	}
}

func decodePointer(path string) ([]string, bool) {
	if path == "" {
		return []string{}, true
	}
	if !strings.HasPrefix(path, "/") {
		return nil, false
	}
	raw := strings.Split(path[1:], "/")
	out := make([]string, 0, len(raw))
	for _, tok := range raw {
		var b strings.Builder
		for i := 0; i < len(tok); i++ {
			if tok[i] == '~' {
				if i+1 >= len(tok) {
					return nil, false
				}
				switch tok[i+1] {
				case '0':
					b.WriteByte('~')
				case '1':
					b.WriteByte('/')
				default:
					return nil, false
				}
				i++
				continue
			}
			b.WriteByte(tok[i])
		}
		out = append(out, b.String())
	}
	return out, true
}

func getAt(root any, tokens []string) (any, bool) {
	cur := root
	for _, tok := range tokens {
		switch c := cur.(type) {
		case map[string]any:
			nxt, ok := c[tok]
			if !ok {
				return nil, false
			}
			cur = nxt
		case []any:
			idx, err := strconv.Atoi(tok)
			if err != nil || idx < 0 || idx >= len(c) {
				return nil, false
			}
			cur = c[idx]
		default:
			return nil, false
		}
	}
	return cur, true
}

func setAt(root *any, tokens []string, value any) bool {
	if len(tokens) == 0 {
		*root = value
		return true
	}
	parent, ok := getAt(*root, tokens[:len(tokens)-1])
	if !ok {
		return false
	}
	last := tokens[len(tokens)-1]
	switch p := parent.(type) {
	case map[string]any:
		p[last] = value
		return true
	case []any:
		idx, err := strconv.Atoi(last)
		if err != nil || idx < 0 || idx >= len(p) {
			return false
		}
		p[idx] = value
		return true
	default:
		return false
	}
}

func applyPatchOperation(root *any, op patchOperation) (bool, string) {
	tokens, ok := decodePointer(op.Path)
	if !ok {
		return false, "invalid path"
	}
	switch op.Op {
	case "ArrayAdd":
		target, ok := getAt(*root, tokens)
		if !ok {
			return false, "path does not exist"
		}
		arr, ok := target.([]any)
		if !ok {
			return false, "path does not refer to an array"
		}
		for _, v := range arr {
			if reflect.DeepEqual(v, op.Value) {
				return true, "patch applied"
			}
		}
		arr = append(arr, op.Value)
		if !setAt(root, tokens, arr) {
			return false, "invalid path"
		}
		return true, "patch applied"
	case "ArrayRemove":
		target, ok := getAt(*root, tokens)
		if !ok {
			return false, "path does not exist"
		}
		arr, ok := target.([]any)
		if !ok {
			return false, "path does not refer to an array"
		}
		for i, v := range arr {
			if reflect.DeepEqual(v, op.Value) {
				arr = append(arr[:i], arr[i+1:]...)
				break
			}
		}
		if !setAt(root, tokens, arr) {
			return false, "invalid path"
		}
		return true, "patch applied"
	case "ObjectAdd":
		if len(tokens) == 0 {
			return false, "invalid path"
		}
		parentTokens := tokens[:len(tokens)-1]
		key := tokens[len(tokens)-1]
		target, ok := getAt(*root, parentTokens)
		if !ok {
			return false, "path does not exist"
		}
		obj, ok := target.(map[string]any)
		if !ok {
			return false, "path does not refer to an object"
		}
		if _, exists := obj[key]; !exists {
			obj[key] = op.Value
		}
		return true, "patch applied"
	default:
		return false, "invalid patch operation"
	}
}
